-- 167-sync-malaysia-course-image-url.sql
--
-- Sync Malaysia (store_id=2) course_image_url EAV values from the local DB to
-- production so both environments point at the same Cloudflare R2 covers.
-- Both environments share one R2 bucket, so copying the URL string is enough.
--
-- Generated 2026-05-26 from local courses_backupDB (486 products).
-- Idempotent: INSERT ... ON DUPLICATE KEY UPDATE on the unique
-- (entity_id, attribute_id, store_id) key. Re-running is a no-op.

ON DUPLICATE KEY UPDATE value = VALUES(value);

-- Refresh the flat-catalog Malaysia view so the storefront and admin grid
-- (which read from catalog_product_flat_<store_id> when flat is on) see the
-- new URLs without waiting for the next full reindex.
UPDATE catalog_product_flat_2 f
JOIN catalog_product_entity_varchar v
  ON v.entity_id = f.entity_id
 AND v.attribute_id = 203
 AND v.store_id = 2
SET f.course_image_url = v.value;
